import React, { useState } from 'react';
import { authAPI } from './api';

function LoginPage({ onLogin }) {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setLoading(true);

    const result = await authAPI.login(username, password);

    if (result.success) {
      onLogin();
    } else {
      setError(result.message || 'Неверное имя пользователя или пароль');
    }

    setLoading(false);
  };

  return (
    <div className="login-container">
      <div className="login-box">
        <h1>Лабораторная работа №2</h1>
        <h2>Проверка попадания точки в область</h2>

        <div className="student-info">
          <p><strong>ФИО:</strong> Ваше ФИО</p>
          <p><strong>Группа:</strong> PXXXX</p>
          <p><strong>Вариант:</strong> XXXX</p>
        </div>

        <form onSubmit={handleSubmit} className="login-form">
          <h3>Вход в систему</h3>

          <div className="form-group">
            <label htmlFor="username">Логин:</label>
            <input
              type="text"
              id="username"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              required
              disabled={loading}
              placeholder="Введите логин"
            />
          </div>

          <div className="form-group">
            <label htmlFor="password">Пароль:</label>
            <input
              type="password"
              id="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              required
              disabled={loading}
              placeholder="Введите пароль"
            />
          </div>

          {error && <div className="error-message">{error}</div>}

          <button
            type="submit"
            className="login-btn"
            disabled={loading}
          >
            {loading ? 'Вход...' : 'Войти'}
          </button>

          <div className="test-credentials">
            <p>Для тестирования:</p>
            <p>admin / admin123 (если создан)</p>
            <p>Или зарегистрируйтесь через curl</p>
          </div>
        </form>
      </div>
    </div>
  );
}

export default LoginPage;
